using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private static readonly List<Department> Departments =
    [
        new() { Id = 1, Code = "CS",   Name = "Computer Science",        Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Code = "MATH", Name = "Mathematics",             Description = "Exploration of abstract structures, quantity, and change." },
        new() { Id = 3, Code = "PHYS", Name = "Physics",                 Description = "Understanding matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Code = "ENG",  Name = "English",                 Description = "Literature, writing, and critical analysis of texts." },
        new() { Id = 5, Code = "HIST", Name = "History",                 Description = "Examination of past events and their impact on the present." },
        new() { Id = 6, Code = "BIO",  Name = "Biology",                 Description = "Study of living organisms and life processes." },
    ];

    private static readonly List<Course> Courses =
    [
        // Computer Science
        new() { Id = 1,  CourseCode = "CS 101",   Title = "Introduction to Programming",     Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.",                                                    Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM",    InstructorName = "Dr. Alice Chen",      InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published extensively on CS pedagogy.",                  DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 2,  CourseCode = "CS 201",   Title = "Data Structures & Algorithms",    Description = "A deep dive into fundamental data structures (trees, graphs, hash tables) and algorithm design. Prerequisites: CS 101.",                                                                                             Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM",      InstructorName = "Dr. Bob Martinez",    InstructorBio = "Dr. Martinez researches algorithm optimization and has won multiple teaching awards.",                                               DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 3,  CourseCode = "CS 310",   Title = "Database Systems",                Description = "Relational database design, SQL, normalization, indexing, and an introduction to NoSQL databases.",                                                                                                                    Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM",        InstructorName = "Dr. Carol Wu",        InstructorBio = "Dr. Wu spent a decade in industry building large-scale database systems before joining academia.",                                   DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
        new() { Id = 4,  CourseCode = "CS 450",   Title = "Artificial Intelligence",         Description = "Survey of AI techniques including search, machine learning, natural language processing, and neural networks.",                                                                                                         Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM",        InstructorName = "Dr. Alice Chen",      InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published extensively on CS pedagogy.",                  DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },

        // Mathematics
        new() { Id = 5,  CourseCode = "MATH 101", Title = "Calculus I",                      Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.",                                                                                                            Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM",  InstructorName = "Dr. David Park",      InstructorBio = "Dr. Park is a renowned mathematician specializing in analysis and has authored three textbooks.",                                    DepartmentId = 2, DepartmentName = "Mathematics",      IsFeatured = true },
        new() { Id = 6,  CourseCode = "MATH 201", Title = "Linear Algebra",                  Description = "Vector spaces, linear transformations, matrices, eigenvalues, and applications.",                                                                                                                                      Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM",       InstructorName = "Dr. Elena Rossi",     InstructorBio = "Dr. Rossi's research focuses on computational linear algebra and numerical methods.",                                                DepartmentId = 2, DepartmentName = "Mathematics",      IsFeatured = false },
        new() { Id = 7,  CourseCode = "MATH 301", Title = "Probability & Statistics",        Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.",                                                                                                                    Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM",   InstructorName = "Dr. David Park",      InstructorBio = "Dr. Park is a renowned mathematician specializing in analysis and has authored three textbooks.",                                    DepartmentId = 2, DepartmentName = "Mathematics",      IsFeatured = false },

        // Physics
        new() { Id = 8,  CourseCode = "PHYS 101", Title = "General Physics I",               Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions. Corequisite: MATH 101.",                                                                                                                          Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM",  InstructorName = "Dr. Frank Nguyen",    InstructorBio = "Dr. Nguyen is an experimental physicist whose research focuses on condensed matter physics.",                                        DepartmentId = 3, DepartmentName = "Physics",          IsFeatured = false },
        new() { Id = 9,  CourseCode = "PHYS 201", Title = "Electromagnetism",                Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.",                                                                                                                                Credits = 4, Schedule = "Tue/Thu 2:00–3:20 PM",        InstructorName = "Dr. Grace Kim",       InstructorBio = "Dr. Kim's research in photonics has been published in leading physics journals worldwide.",                                          DepartmentId = 3, DepartmentName = "Physics",          IsFeatured = false },

        // English
        new() { Id = 10, CourseCode = "ENG 101",  Title = "Freshman Composition",            Description = "Develop college-level writing skills through essays, research papers, and peer review workshops.",                                                                                                                     Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM",    InstructorName = "Prof. Hannah Lee",    InstructorBio = "Prof. Lee is a published author and writing coach with expertise in rhetoric and composition.",                                      DepartmentId = 4, DepartmentName = "English",          IsFeatured = false },
        new() { Id = 11, CourseCode = "ENG 220",  Title = "American Literature",             Description = "Survey of American literary works from the colonial period to the present, examining themes of identity, freedom, and society.",                                                                                        Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM",   InstructorName = "Dr. Ian Brooks",      InstructorBio = "Dr. Brooks specializes in 20th-century American fiction and has received fellowships from the NEH.",                                 DepartmentId = 4, DepartmentName = "English",          IsFeatured = true },

        // History
        new() { Id = 12, CourseCode = "HIST 101", Title = "World History to 1500",           Description = "A global survey from the rise of civilizations through the late medieval period, covering major cultures, trade networks, and empires.",                                                                                Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM",        InstructorName = "Dr. Julia Adams",     InstructorBio = "Dr. Adams is a medievalist who has conducted archaeological fieldwork across Europe and the Middle East.",                            DepartmentId = 5, DepartmentName = "History",          IsFeatured = false },
        new() { Id = 13, CourseCode = "HIST 250", Title = "Modern European History",         Description = "Europe from the Enlightenment to the present: revolutions, industrialization, world wars, and the European Union.",                                                                                                     Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM",        InstructorName = "Dr. Karl Weber",      InstructorBio = "Dr. Weber is a specialist in modern German history and European political thought.",                                                 DepartmentId = 5, DepartmentName = "History",          IsFeatured = false },

        // Biology
        new() { Id = 14, CourseCode = "BIO 101",  Title = "General Biology",                 Description = "Introduction to cell biology, genetics, evolution, and ecology. Includes lab component.",                                                                                                                              Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM",    InstructorName = "Dr. Laura Singh",     InstructorBio = "Dr. Singh is a geneticist whose lab focuses on CRISPR applications in plant biology.",                                               DepartmentId = 6, DepartmentName = "Biology",          IsFeatured = true },
        new() { Id = 15, CourseCode = "BIO 310",  Title = "Microbiology",                    Description = "Study of microorganisms including bacteria, viruses, and fungi. Emphasis on medical and environmental microbiology.",                                                                                                   Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM",      InstructorName = "Dr. Michael Torres",  InstructorBio = "Dr. Torres has published over 50 papers on antimicrobial resistance and infectious disease.",                                        DepartmentId = 6, DepartmentName = "Biology",          IsFeatured = false },
    ];

    public IReadOnlyList<Department> GetDepartments() => Departments;

    public Department? GetDepartment(int id) => Departments.Find(d => d.Id == id);

    public IReadOnlyList<Course> GetAllCourses() => Courses;

    public IReadOnlyList<Course> GetFeaturedCourses() => Courses.Where(c => c.IsFeatured).ToList();

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = Courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => Courses.Find(c => c.Id == id);

    public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
        Courses.Where(c => c.DepartmentId == departmentId).ToList();
}

