@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@rendermode InteractiveServer
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses…"
               @bind="SearchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@{
    var results = Catalog.SearchCourses(SearchTerm, SelectedDepartmentId);
}

@if (results.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in results)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string? SearchTerm { get; set; }
    private int SelectedDepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4>Schedule</h4>
            <p><span class="badge bg-secondary">@course.Schedule</span></p>

            <h4>Credits</h4>
            <p><strong>@course.Credits</strong> credit hours</p>

            <a href="enroll?courseId=@course.Id" class="btn btn-success mt-2">Request Enrollment</a>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><strong>Instructor</strong></div>
                <div class="card-body">
                    <h5 class="card-title">@course.InstructorName</h5>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>

            <div class="card mt-3">
                <div class="card-header"><strong>Department</strong></div>
                <div class="card-body">
                    <a href="departments/@course.DepartmentId">@course.DepartmentName</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/departments/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>@(department?.Name ?? "Department Not Found")</PageTitle>

@if (department is null)
{
    <div class="alert alert-warning">Department not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="departments">Departments</a></li>
            <li class="breadcrumb-item active" aria-current="page">@department.Name</li>
        </ol>
    </nav>

    <h1>@department.Code — @department.Name</h1>
    <p class="lead">@department.Description</p>

    <h3 class="mt-4">Courses</h3>

    @if (courses.Count == 0)
    {
        <div class="alert alert-info">No courses listed for this department.</div>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.Credits</td>
                        <td>@course.Schedule</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter] public int Id { get; set; }
    private Department? department;
    private IReadOnlyList<Course> courses = [];

    protected override void OnInitialized()
    {
        department = Catalog.GetDepartment(Id);
        if (department is not null)
            courses = Catalog.GetCoursesByDepartment(department.Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@rendermode InteractiveServer
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@Model.FullName</strong> (ID: @Model.StudentId).
           Your enrollment request for <strong>@SelectedCourseName</strong> has been received.
           You will be notified by email once it is processed.</p>
        <a href="enroll" class="btn btn-outline-primary mt-2" @onclick="Reset" @onclick:preventDefault>Submit Another Request</a>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="mt-3">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name</label>
            <InputText id="fullName" class="form-control" @bind-Value="Model.FullName" />
            <ValidationMessage For="() => Model.FullName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                <option value="0">— Select a course —</option>
                @foreach (var course in Catalog.GetAllCourses())
                {
                    <option value="@course.Id">@course.CourseCode — @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private EnrollmentRequest Model { get; set; } = new();
    private bool Submitted { get; set; }
    private string SelectedCourseName => Catalog.GetCourse(Model.CourseId)?.Title ?? "Unknown Course";

    protected override void OnInitialized()
    {
        if (PreselectedCourseId.HasValue)
            Model.CourseId = PreselectedCourseId.Value;
    }

    private void HandleSubmit()
    {
        // In a real application this would persist the enrollment request.
        Submitted = true;
    }

    private void Reset()
    {
        Model = new EnrollmentRequest();
        Submitted = false;
    }
}

